 65→function serializeSvg(svgElement) {
 66→  const clone = svgElement.cloneNode(true);
 67→  clone.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
 68→  clone.setAttribute('xmlns:xlink', 'http://www.w3.org/1999/xlink');
 69→  clone.removeAttribute('style');
 70→
 71→  if (!clone.getAttribute('viewBox')) {
 72→    const width = clone.getAttribute('width') || '100';
 73→    const height = clone.getAttribute('height') || '100';
 74→    clone.setAttribute('viewBox', `0 0 ${width} ${height}`);
 75→  }
 76→
 77→  inlineComputedStyles(svgElement, clone);
 78→  return new XMLSerializer().serializeToString(clone);
 79→}
