 81→function createImageFromSvgString(svgString) {
 82→  return new Promise((resolve, reject) => {
 83→    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
 84→    const url = URL.createObjectURL(blob);
 85→    const image = new Image();
 86→    image.onload = () => {
 87→      URL.revokeObjectURL(url);
 88→      resolve(image);
 89→    };
 90→    image.onerror = (error) => {
 91→      URL.revokeObjectURL(url);
 92→      reject(error);
 93→    };
 94→    image.src = url;
 95→  });
 96→}
 97→
 98→function getCanvasScaleFromDpi(dpi) {
 99→  return Math.max(1, (Number(dpi) || DEFAULT_PNG_DPI) / MM_PER_INCH);
100→}
101→
102→async function renderSvgToCanvas(svgElement, dpi = DEFAULT_PNG_DPI) {
103→  const width = Number(svgElement.getAttribute('width')) || 100;
104→  const height = Number(svgElement.getAttribute('height')) || 100;
105→  const scale = getCanvasScaleFromDpi(dpi);
106→  const canvas = document.createElement('canvas');
107→  canvas.width = Math.max(1, Math.round(width * scale));
108→  canvas.height = Math.max(1, Math.round(height * scale));
109→  const context = canvas.getContext('2d');
110→  context.fillStyle = '#ffffff';
111→  context.fillRect(0, 0, canvas.width, canvas.height);
112→  context.scale(scale, scale);
113→  [...svgElement.children].forEach((child) => drawElementToCanvas(context, child));
114→  return { canvas };
115→}
