568→function beginNode(builder, element) {
569→  const localMatrix = getLocalMatrix(element);
570→  const tagName = element.tagName.toLowerCase();
571→  const needsClip = tagName === 'svg' && element !== getExportSvg();
572→  const shouldWrap = needsClip || !matrixIsIdentity(localMatrix);
573→
574→  if (!shouldWrap) return false;
575→
576→  builder.write('q');
577→  if (!matrixIsIdentity(localMatrix)) {
578→    builder.write(`${fmt(localMatrix.a)} ${fmt(localMatrix.b)} ${fmt(localMatrix.c)} ${fmt(localMatrix.d)} ${fmt(localMatrix.e)} ${fmt(localMatrix.f)} cm`);
579→  }
580→
581→  if (needsClip) {
582→    const width = Number(element.getAttribute('width')) || 0;
583→    const height = Number(element.getAttribute('height')) || 0;
584→    builder.write(`0 0 ${fmt(width)} ${fmt(height)} re W n`);
585→  }
586→
587→  return true;
588→}
589→
590→function endNode(builder, wrapped) {
