641→function fillAndStrokeCanvasPath(context, style) {
642→  const hasFill = Boolean(style.fill);
643→  const hasStroke = Boolean(style.stroke && style.strokeWidth > 0);
644→
645→  if (hasFill) {
646→    context.globalAlpha = style.fillOpacity;
647→    context.fill();
648→  }
649→  if (hasStroke) {
