    Math.abs(matrix.a - 1) < 1e-8
    && Math.abs(matrix.b) < 1e-8
    && Math.abs(matrix.c) < 1e-8
    && Math.abs(matrix.d - 1) < 1e-8
    && Math.abs(matrix.e) < 1e-8
    && Math.abs(matrix.f) < 1e-8
