function parseViewBox(svgElement) {
  const values = parseNumberList(svgElement.getAttribute('viewBox') || '');
  if (values.length !== 4) {
    return {
      minX: 0,
      minY: 0,
      width: Number(svgElement.getAttribute('width')) || 0,
      height: Number(svgElement.getAttribute('height')) || 0,
    };
  }
  return {
    minX: values[0],
    minY: values[1],
    width: values[2],
    height: values[3],
  };
